mapper.select:
SELECT ATTD_NO, EMP_NO, EMP_NM, DEPT_NM, WORK_DT, IN_DTM, LATE_YN, OUT_DTM, OUT_AUTO_YN, ATTD_STAT_CD, REMARK, CRT_DTM, MOD_DTM FROM ( SELECT ROWNUM AS RNUM, T.* FROM ( SELECT A.ATTD_NO, E.EMP_NO, E.EMP_NM, D.DEPT_NM, #{workDt} AS WORK_DT, A.IN_DTM, A.LATE_YN, A.OUT_DTM, A.OUT_AUTO_YN,
CASE /* 0) 수동으로 저장된 상태가 있으면 그걸 우선 */ WHEN A.ATTD_STAT_CD IS NOT NULL THEN A.ATTD_STAT_CD
/* 1) 연차(일정에 오늘 포함) */ WHEN EXISTS ( SELECT 1 FROM SCHEDULE S WHERE S.EMP_NO = E.EMP_NO AND S.DEL_YN = 'N' AND S.SCHD_DIV_CD = 'VACATION' AND TRUNC(S.SCHD_ST_DTM) <= #{workDt} AND TRUNC(S.SCHD_ED_DTM) >= #{workDt} ) THEN 'VACATION'
/* 2) 지각 (출근 기록이 있고 09:10 이후라면 퇴근 여부와 상관없이 지각 유지) */ WHEN TO_CHAR(A.IN_DTM, 'HH24:MI') > '09:10' THEN 'LATE'
/* 3) 퇴근 기록 있으면 최종 퇴근 */ WHEN A.OUT_DTM IS NOT NULL THEN 'OFF'
/* 4) 출근 기록 없으면 결근 */ WHEN A.IN_DTM IS NULL THEN 'ABSENT'
/* 5) 정상 출근 */ ELSE 'PRESENT' END AS ATTD_STAT_CD,
A.REMARK, A.CRT_DTM, A.MOD_DTM FROM EMP E JOIN DEPT D ON E.DEPT_CD = D.DEPT_CD LEFT JOIN ATTENDANCE A ON E.EMP_NO = A.EMP_NO AND A.WORK_DT = #{workDt}
AND E.EMP_NO = #{empNo}
AND E.EMP_NM LIKE '%' || #{empNm} || '%'
AND D.DEPT_NM = #{deptNm}
AND ( CASE WHEN A.ATTD_STAT_CD IS NOT NULL THEN A.ATTD_STAT_CD
WHEN EXISTS ( SELECT 1 FROM SCHEDULE S WHERE S.EMP_NO = E.EMP_NO AND S.DEL_YN = 'N' AND S.SCHD_DIV_CD = 'VACATION' AND TRUNC(S.SCHD_ST_DTM) <= #{workDt} AND TRUNC(S.SCHD_ED_DTM) >= #{workDt} ) THEN 'VACATION' WHEN TO_CHAR(A.IN_DTM,'HH24:MI') > '09:10' THEN 'LATE' WHEN A.OUT_DTM IS NOT NULL THEN 'OFF' WHEN A.IN_DTM IS NULL THEN 'ABSENT' ELSE 'PRESENT' END ) = #{attdStatCd}
ORDER BY E.EMP_NO ) T WHERE ROWNUM <= #{endRow} ) WHERE RNUM >= #{startRow}

SELECT COUNT(*)
FROM EMP E
JOIN DEPT D ON E.DEPT_CD = D.DEPT_CD
LEFT JOIN ATTENDANCE A
  ON E.EMP_NO = A.EMP_NO
 AND A.WORK_DT = #{workDt}


      AND E.EMP_NO = #{empNo}


      AND E.EMP_NM LIKE '%' || #{empNm} || '%'


      AND D.DEPT_NM = #{deptNm}


      AND (
          CASE
            WHEN EXISTS (
                  SELECT 1
                  FROM SCHEDULE S
                  WHERE S.EMP_NO = E.EMP_NO
                    AND S.DEL_YN = 'N'
                    AND S.SCHD_DIV_CD = 'VACATION'
                    AND TRUNC(S.SCHD_ST_DTM) <= #{workDt}
                    AND TRUNC(S.SCHD_ED_DTM) >= #{workDt}
            ) THEN 'VACATION'
            WHEN TO_CHAR(A.IN_DTM,'HH24:MI') > '09:10' THEN 'LATE'
            WHEN A.OUT_DTM IS NOT NULL THEN 'OFF'
            WHEN A.IN_DTM IS NULL THEN 'ABSENT'
            ELSE 'PRESENT'
          END
      ) = #{attdStatCd}
